const body = $node["Webhook"].json.body || {};
const messages = Array.isArray(body.messages) ? body.messages : [];
const transcript = (typeof body.transcript === 'string' && body.transcript.trim().length > 0)
  ? body.transcript
  : messages
      .map((m) => (m.role === 'user' ? 'Client' : 'Therapist') + ': ' + String(m.content || ''))
      .join('\n');

return [{
  json: {
    session_id: body.session_id || '',
    profile_id: body.profile_id || '',
    profile: body.profile || {},
    session: body.session || {},
    phase_context: body.phase_context || {},
    currentPhase: body.currentPhase || body.phase_context?.current_phase || {},
    messages,
    transcript,
    memories: Array.isArray(body.memories) ? body.memories : [],
    current_memory: body.current_memory || null,
    recent_case_notes: Array.isArray(body.recent_case_notes) ? body.recent_case_notes : [],
    active_tasks: Array.isArray(body.active_tasks) ? body.active_tasks : [],
    assessments: Array.isArray(body.assessments) ? body.assessments : [],
    mood_entries: Array.isArray(body.mood_entries) ? body.mood_entries : [],
    memory_workflow_id: body.memory_workflow_id || 'REPLACE_WITH_MEMORY_WORKFLOW_ID',
    summary_workflow_id: body.summary_workflow_id || 'REPLACE_WITH_SUMMARY_WORKFLOW_ID',
    readiness_workflow_id: body.readiness_workflow_id || 'REPLACE_WITH_READINESS_WORKFLOW_ID'
  }
}];

const payloads = $input.all().map((i) => i.json || {});
const memory = payloads.find((p) => p.branch === 'memory');
const summary = payloads.find((p) => p.branch === 'summary');
const readiness = payloads.find((p) => p.branch === 'readiness');

if (!memory) throw new Error('MERGE_ERROR: Missing memory branch response');
if (!summary) throw new Error('MERGE_ERROR: Missing summary branch response');
if (!readiness) throw new Error('MERGE_ERROR: Missing readiness branch response');
if (!Array.isArray(memory.extracted_memories) || memory.extracted_memories.length === 0) {
  throw new Error('MERGE_ERROR: Invalid extracted_memories from memory workflow');
}
if (!summary.session_summary || !summary.case_notes_base) {
  throw new Error('MERGE_ERROR: Invalid summary payload');
}
if (!['not_ready', 'approaching', 'ready'].includes(String(readiness.readiness_for_next_phase || ''))) {
  throw new Error('MERGE_ERROR: Invalid readiness_for_next_phase');
}

const cnb = summary.case_notes_base;
const rc = Number(readiness.readiness_confidence);
const riskLevel = String(readiness.risk_level || 'low').toLowerCase();
const majorRisk = ['high', 'critical'].includes(riskLevel) || Boolean(readiness.requires_escalation) || Boolean(readiness.crisis_detected);
const completionScoreRaw = Number(summary.completion_score ?? summary.session_summary?.completion_score ?? (String(readiness.readiness_for_next_phase) === 'ready' ? 0.8 : 0.45));
const completionScore = Number.isFinite(completionScoreRaw) ? Math.max(0, Math.min(1, completionScoreRaw)) : 0.45;
const objectiveSignal = typeof summary.objective_met === 'boolean' ? summary.objective_met : (completionScore >= 0.7 && !majorRisk);
const objectiveMet = majorRisk ? false : objectiveSignal;
const recommendedNextAction = majorRisk
  ? (Boolean(readiness.requires_escalation) ? 'escalate' : 'stabilize')
  : (objectiveMet ? 'advance' : 'revisit');
const shouldAdvance = !majorRisk && objectiveMet && String(readiness.readiness_for_next_phase) === 'ready';

return [{
  json: {
    case_notes: {
      presenting_concern: String(cnb.presenting_concern || ''),
      dynamic_theme: String(cnb.dynamic_theme || ''),
      phase_progress: String(cnb.phase_progress || ''),
      readiness_for_next_phase: readiness.readiness_for_next_phase,
      risk_level: riskLevel,
      requires_escalation: Boolean(readiness.requires_escalation),
      crisis_detected: Boolean(readiness.crisis_detected),
      readiness_rationale: String(readiness.readiness_rationale || ''),
      readiness_confidence: Number.isFinite(rc) ? Math.min(1, Math.max(0, rc)) : 0.5,
    },
    session_summary: summary.session_summary,
    extracted_tasks: Array.isArray(summary.extracted_tasks) ? summary.extracted_tasks : [],
    extracted_memories: memory.extracted_memories,
    suggested_pathway: typeof summary.suggested_pathway === 'string' ? summary.suggested_pathway : null,
    objective_met: objectiveMet,
    completion_score: completionScore,
    objective_confidence: Number.isFinite(Number(summary.objective_confidence)) ? Math.max(0, Math.min(1, Number(summary.objective_confidence))) : completionScore,
    recommended_adjustments: summary.recommended_adjustments && typeof summary.recommended_adjustments === 'object' ? summary.recommended_adjustments : {},
    session_transition: {
      objective_met: objectiveMet,
      session_transition: objectiveMet,
      recommended_next_action: recommendedNextAction
    },
    phase_transition: {
      phase_transition: shouldAdvance,
      should_advance: shouldAdvance,
      rationale: shouldAdvance ? 'objective_met_and_ready' : 'continue_current_phase'
    },
    agent_meta: {
      architecture: 'parent_execute_workflow_children',
      memory_agent_model: memory.model || 'gpt-4o-mini',
      summary_agent_model: summary.model || 'gpt-4o-mini',
      readiness_agent_model: readiness.model || 'gpt-4o-mini'
    }
  }
}];
